import os
from pathlib import Path


def delete_user_file(filename):
    """
    Securely deletes a user's uploaded file from the 'uploads' directory.
    
    Args:
        filename: The filename provided by the user
        
    Returns:
        bool: True if file was deleted successfully, False otherwise
        
    Raises:
        ValueError: If the path is invalid or attempts path traversal
        FileNotFoundError: If the file doesn't exist
    """
    base_dir = Path('uploads').resolve()
    
    # Reject absolute paths
    if os.path.isabs(filename):
        raise ValueError("Absolute paths are not allowed")
    
    # Reject paths with traversal segments
    if '..' in Path(filename).parts:
        raise ValueError("Path traversal segments are not allowed")
    
    # Construct and canonicalize the full path
    full_path = (base_dir / filename).resolve()
    
    # Verify the resolved path is within the allowed directory
    try:
        full_path.relative_to(base_dir)
    except ValueError:
        raise ValueError("Path is outside the allowed directory")
    
    # Check if file exists
    if not full_path.exists():
        raise FileNotFoundError(f"File '{filename}' not found")
    
    # Check if it's actually a file (not a directory)
    if not full_path.is_file():
        raise ValueError("Path does not point to a file")
    
    # Delete the file
    os.remove(full_path)
